import java.util.*; class Student implements Comparable<Student>{ int roll; Student(int r){roll=r;} public int compareTo(Student s){ return roll-s.roll; } public String toString(){ return String.valueOf(roll);} } public class Four{ public static void main(String[] args){ List<Student> list=new ArrayList<>(); list.add(new Student(3)); list.add(new Student(1)); list.add(new Student(2)); Collections.sort(list); System.out.println(list); }}